// src/components/Sidebar.js
import React from "react";
import { NavLink, useNavigate } from "react-router-dom";
import "./Sidebar.css";

const HomeIcon = () => (
  <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
    <path d="M3 9.5L12 3l9 6.5V20a1 1 0 0 1-1 1H4a1 1 0 0 1-1-1V9.5z" />
    <path d="M9 21V12h6v9" />
  </svg>
);

const PracticeIcon = () => (
  <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
    <path d="M12 1a3 3 0 0 1 3 3v8a3 3 0 0 1-6 0V4a3 3 0 0 1 3-3z" />
    <path d="M19 10a7 7 0 0 1-14 0M12 19v4M8 23h8" />
  </svg>
);

const ScenariosIcon = () => (
  <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
    <rect x="3" y="3" width="7" height="7" rx="1" />
    <rect x="14" y="3" width="7" height="7" rx="1" />
    <rect x="3" y="14" width="7" height="7" rx="1" />
    <rect x="14" y="14" width="7" height="7" rx="1" />
  </svg>
);

const ProgressIcon = () => (
  <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
    <polyline points="22 12 18 12 15 21 9 3 6 12 2 12" />
  </svg>
);

const SettingsIcon = () => (
  <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
    <circle cx="12" cy="12" r="3" />
    <path d="M19.07 4.93a10 10 0 0 1 0 14.14M4.93 4.93a10 10 0 0 0 0 14.14" />
  </svg>
);

const LogoutIcon = () => (
  <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2">
    <path d="M17 16l4-4-4-4M21 12H9M13 4H5a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h8" />
  </svg>
);

const LogoIcon = () => (
  <svg viewBox="0 0 40 40" fill="none" width="26" height="26">
    <defs>
      <linearGradient id="sidebarLogoGradient" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#a99dff" />
        <stop offset="100%" stopColor="#5b4fcf" />
      </linearGradient>
    </defs>
    <path
      d="M28 10C25.3 7.3 21.8 5.5 18 5.5C10.5 5.5 4.5 11.5 4.5 19C4.5 26.5 10.5 32.5 18 32.5C21.8 32.5 25.3 30.7 28 28"
      stroke="url(#sidebarLogoGradient)"
      strokeWidth="4"
      strokeLinecap="round"
    />
    <path
      d="M32 9 L33.2 12 L36 13 L33.2 14 L32 17 L30.8 14 L28 13 L30.8 12 Z"
      fill="url(#sidebarLogoGradient)"
    />
  </svg>
);

const NAV_ITEMS = [
  { to: "/dashboard", label: "Home", icon: <HomeIcon /> },
  { to: "/practice", label: "Practice", icon: <PracticeIcon /> },
  { to: "/practice", label: "Scenarios", icon: <ScenariosIcon /> },
  { to: "/dashboard", label: "Progress", icon: <ProgressIcon /> },
  { divider: true },
  { to: "/dashboard", label: "Settings", icon: <SettingsIcon /> },
];

export default function Sidebar({ user, onLogout }) {
  const navigate = useNavigate();

  return (
    <aside className="sidebar">
      <div className="sidebar-logo" onClick={() => navigate("/dashboard")}>
        <div className="sidebar-logo-icon">
          <LogoIcon />
        </div>

        <div className="sidebar-logo-text">
          <span className="sidebar-logo-name">CLARIO</span>
          <span className="sidebar-logo-sub">AI SPEECH COACH</span>
        </div>
      </div>

      <nav className="sidebar-nav">
        {NAV_ITEMS.map((item, index) => {
          if (item.divider) {
            return <div key={`divider-${index}`} className="sidebar-divider" />;
          }

          return (
            <NavLink
              key={`${item.label}-${index}`}
              to={item.to}
              className={({ isActive }) =>
                `sidebar-nav-item${isActive ? " active" : ""}`
              }
            >
              <span className="sidebar-nav-icon">{item.icon}</span>
              <span className="sidebar-nav-label">{item.label}</span>
            </NavLink>
          );
        })}

        <button className="sidebar-nav-item sidebar-logout-link" onClick={onLogout}>
          <span className="sidebar-nav-icon">
            <LogoutIcon />
          </span>
          <span className="sidebar-nav-label">Log out</span>
        </button>
      </nav>

      <div className="sidebar-upgrade">
        <div className="sidebar-upgrade-icon">♛</div>
        <div className="sidebar-upgrade-text">
          <strong>Go Premium</strong>
          <span>Unlock advanced insights, personalized tips, and unlimited practice.</span>
        </div>
        <button className="sidebar-upgrade-btn">Upgrade Now</button>
      </div>

      <div className="sidebar-wave">
        <svg viewBox="0 0 220 80" preserveAspectRatio="none">
          <path
            d="M0 38 Q55 0 110 38 Q165 76 220 38 L220 80 L0 80 Z"
            fill="rgba(124,108,252,0.13)"
          />
          <path
            d="M0 55 Q55 20 110 55 Q165 90 220 55 L220 80 L0 80 Z"
            fill="rgba(124,108,252,0.08)"
          />
        </svg>
      </div>
    </aside>
  );
}
